import React from "react";
import { motion } from "framer-motion";
import { FaInfoCircle } from "react-icons/fa";

const HomeAboutSection = () => {
  return (
    <motion.div
      className="container my-5"
      initial={{ opacity: 0, y: 50 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ duration: 1 }}
      viewport={{ once: true }}
    >
      <div className="row align-items-center">
        <div className="col-md-2 text-center mb-3 mb-md-0">
          <FaInfoCircle className="text-warning" size={60} />
        </div>
        <div className="col-md-10">
          <h3 className="text-primary font-weight-bold mb-3">من نحن</h3>
          <p className="lead text-muted">
            صناع الحياة الإسماعيلية هي مجموعة شبابية تطوعية تهدف لنشر الخير وتنمية المجتمع من خلال
            العمل الجماعي المنظم، ونشر قيم التعاون والرحمة والتعليم.
          </p>
        </div>
      </div>
    </motion.div>
  );
};

export default HomeAboutSection;
